use bat::line_range::{LineRange, LineRanges};

#[test]
fn test_parse_single_line() {
    let range = LineRange::from("5");
    assert!(range.is_ok());
}

#[test]
fn test_parse_range() {
    let range = LineRange::from("10:20");
    assert!(range.is_ok());
}

#[test]
fn test_parse_open_end() {
    let range = LineRange::from("5:");
    assert!(range.is_ok());
}
